"use client";

import {
  Sequence,
  interpolate,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";

export interface GlassCodeBlockProps {
  code?: string;
  title?: string;
  width?: number;
  height?: number;
  fontSize?: number;
  glassColor?: string;
  staggerFrames?: number;
  showTrafficLights?: boolean;
  /** The soft cyan/purple gradient glow behind the glass. On by default. */
  aura?: boolean;
  /**
   * Reveal the first line as a left-to-right typewriter (with a block cursor)
   * instead of the default fade-up; the remaining lines then stagger in only
   * after the first line finishes typing. Off by default.
   */
  typeFirstLine?: boolean;
  /** Typing speed (characters/second) when `typeFirstLine` is on. */
  firstLineCps?: number;
  speed?: number;
  className?: string;
}

/** Frames the first-line typewriter takes — exported so a caller can sync a
 *  camera move to the moment typing completes. */
export function firstLineTypeFrames(
  firstLine: string,
  firstLineCps: number,
  fps: number,
): number {
  return Math.ceil((firstLine.length / firstLineCps) * fps);
}

const FONT_MONO =
  "var(--font-geist-mono), ui-monospace, SFMono-Regular, monospace";

const DEFAULT_CODE = `import { motion } from "remotion";

// Generate a hero scene
export function Hero() {
  const frame = useCurrentFrame();
  const opacity = frame / 30;
  return <h1 style={{ opacity }}>Hello</h1>;
}`;

// Minimal regex tokenizer. NOT a real syntax highlighter — just enough to
// give the eye color anchors. Order matters: comments → strings → keywords.
const KEYWORDS = new Set([
  "import",
  "from",
  "export",
  "function",
  "const",
  "let",
  "var",
  "return",
  "if",
  "else",
  "for",
  "while",
  "new",
  "class",
  "extends",
  "default",
  "true",
  "false",
  "null",
  "undefined",
]);

type Token = {
  text: string;
  kind: "code" | "comment" | "string" | "keyword" | "number";
};

function tokenizeLine(line: string): Token[] {
  // Whole-line comment.
  const trimmed = line.trimStart();
  if (trimmed.startsWith("//")) {
    return [{ text: line, kind: "comment" }];
  }

  const tokens: Token[] = [];
  // Split keeping delimiters: words, strings, numbers, everything else.
  const re = /("[^"]*"|'[^']*'|`[^`]*`|\b\d+\b|\b[A-Za-z_$][\w$]*\b|[^\w"']+)/g;
  let match: RegExpExecArray | null;
  while ((match = re.exec(line)) !== null) {
    const t = match[0];
    const first = t[0];
    if (first === '"' || first === "'" || first === "`") {
      tokens.push({ text: t, kind: "string" });
    } else if (/^\d+$/.test(t)) {
      tokens.push({ text: t, kind: "number" });
    } else if (/^[A-Za-z_$][\w$]*$/.test(t) && KEYWORDS.has(t)) {
      tokens.push({ text: t, kind: "keyword" });
    } else {
      tokens.push({ text: t, kind: "code" });
    }
  }
  return tokens;
}

const TOKEN_COLORS: Record<Token["kind"], string> = {
  code: "#e4e4e7",
  comment: "#52525b",
  string: "#86efac",
  keyword: "#c4b5fd",
  number: "#fcd34d",
};

export function GlassCodeBlock({
  code = DEFAULT_CODE,
  title = "hero.tsx",
  width = 760,
  height = 460,
  fontSize = 16,
  glassColor = "rgba(10, 10, 10, 0.6)",
  staggerFrames = 4,
  showTrafficLights = true,
  aura = true,
  typeFirstLine = false,
  firstLineCps = 30,
  speed = 1,
  className,
}: GlassCodeBlockProps) {
  const { fps } = useVideoConfig();
  const lines = code.split("\n");
  // When the first line types, every later line waits until typing is done.
  const typeDur = typeFirstLine
    ? firstLineTypeFrames(lines[0] ?? "", firstLineCps, fps)
    : 0;

  return (
    <div
      className={className}
      style={{
        position: "absolute",
        inset: 0,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      {/* Animated background hint behind the glass so the blur has something
          to chew on. Pure CSS — no extra deps. */}
      {aura && <BackdropAura />}

      {/* 1px gradient ring acting as a microborder */}
      <div
        style={{
          position: "relative",
          padding: 1,
          borderRadius: 16,
          background:
            "linear-gradient(180deg, rgba(255,255,255,0.18) 0%, rgba(255,255,255,0) 100%)",
          width,
          height,
          boxShadow: "0 50px 120px rgba(0,0,0,0.55)",
        }}
      >
        <div
          style={{
            width: "100%",
            height: "100%",
            borderRadius: 15,
            background: glassColor,
            backdropFilter: "blur(16px)",
            WebkitBackdropFilter: "blur(16px)",
            boxShadow: "inset 0 1px 0 rgba(255,255,255,0.06)",
            display: "flex",
            flexDirection: "column",
            overflow: "hidden",
            fontFamily: FONT_MONO,
          }}
        >
          {/* Chrome */}
          <div
            style={{
              height: 40,
              display: "flex",
              alignItems: "center",
              gap: 8,
              padding: "0 16px",
              borderBottom: "1px solid rgba(255,255,255,0.06)",
            }}
          >
            {showTrafficLights && (
              <>
                <Light color="#ff5f57" />
                <Light color="#febc2e" />
                <Light color="#28c840" />
              </>
            )}
            <div
              style={{
                flex: 1,
                textAlign: "center",
                color: "#a1a1aa",
                fontSize: 12,
                letterSpacing: "0.02em",
              }}
            >
              {title}
            </div>
          </div>

          {/* Code body */}
          <div
            style={{
              flex: 1,
              padding: "20px 24px",
              display: "flex",
              flexDirection: "column",
              gap: 4,
              fontSize,
              lineHeight: 1.55,
            }}
          >
            {lines.map((line, i) => {
              if (typeFirstLine && i === 0) {
                return (
                  <Sequence key={i} from={0} layout="none">
                    <TypedCodeLine
                      line={line}
                      index={i}
                      fontSize={fontSize}
                      cps={firstLineCps}
                      fps={fps}
                      speed={speed}
                    />
                  </Sequence>
                );
              }
              const baseFrom = typeFirstLine
                ? typeDur + (i - 1) * staggerFrames
                : i * staggerFrames;
              return (
                <Sequence
                  key={i}
                  from={Math.round(baseFrom / speed)}
                  layout="none"
                >
                  <CodeLine line={line} index={i} fontSize={fontSize} />
                </Sequence>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

function Light({ color }: { color: string }) {
  return (
    <div
      style={{
        width: 12,
        height: 12,
        borderRadius: "50%",
        background: color,
        opacity: 0.6,
      }}
    />
  );
}

function CodeLine({
  line,
  index,
  fontSize,
}: {
  line: string;
  index: number;
  fontSize: number;
}) {
  const frame = useCurrentFrame();
  const opacity = interpolate(frame, [0, 8], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });
  const ty = interpolate(frame, [0, 8], [4, 0], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  const tokens = tokenizeLine(line);
  // Render an empty line as a half-height spacer so blank lines still take
  // visual space without collapsing the gap.
  if (tokens.length === 0) {
    return <div style={{ height: fontSize * 0.8, opacity }} />;
  }
  return (
    <div
      style={{
        opacity,
        transform: `translateY(${ty}px)`,
        whiteSpace: "pre",
        display: "flex",
        gap: 0,
      }}
    >
      <span style={{ width: 28, color: "#3f3f46", userSelect: "none" }}>
        {String(index + 1).padStart(2, " ")}
      </span>
      <span>
        {tokens.map((t, i) => (
          <span key={i} style={{ color: TOKEN_COLORS[t.kind] }}>
            {t.text}
          </span>
        ))}
      </span>
    </div>
  );
}

function TypedCodeLine({
  line,
  index,
  fontSize,
  cps,
  fps,
  speed,
}: {
  line: string;
  index: number;
  fontSize: number;
  cps: number;
  fps: number;
  speed: number;
}) {
  const frame = useCurrentFrame() * speed;
  const len = line.length;
  const revealed = Math.floor(
    interpolate(frame, [0, (len / cps) * fps], [0, len], {
      extrapolateLeft: "clamp",
      extrapolateRight: "clamp",
    }),
  );
  const visible = line.substring(0, revealed);
  const done = revealed >= len;
  // 2 Hz blink at any framerate.
  const cursorOn = Math.floor((frame / fps) * 2) % 2 === 0;
  const tokens = tokenizeLine(visible);

  return (
    <div
      style={{
        whiteSpace: "pre",
        display: "flex",
        gap: 0,
        alignItems: "center",
      }}
    >
      <span style={{ width: 28, color: "#3f3f46", userSelect: "none" }}>
        {String(index + 1).padStart(2, " ")}
      </span>
      <span>
        {tokens.map((t, i) => (
          <span key={i} style={{ color: TOKEN_COLORS[t.kind] }}>
            {t.text}
          </span>
        ))}
        {!done && cursorOn && (
          <span
            style={{
              display: "inline-block",
              width: fontSize * 0.55,
              height: fontSize,
              background: "#e4e4e7",
              marginLeft: 1,
              transform: "translateY(2px)",
            }}
          />
        )}
      </span>
    </div>
  );
}

function BackdropAura() {
  // Slow, low-amplitude blob behind the glass so the backdrop blur has
  // perceptible content to refract.
  const frame = useCurrentFrame();
  const t = frame / 60;
  const x = 50 + Math.sin(t) * 20;
  const y = 50 + Math.cos(t * 0.7) * 15;
  return (
    <div
      style={{
        position: "absolute",
        inset: 0,
        pointerEvents: "none",
        background: `radial-gradient(circle at ${x}% ${y}%, rgba(56,189,248,0.22), transparent 50%), radial-gradient(circle at ${100 - x}% ${100 - y}%, rgba(168,85,247,0.18), transparent 55%)`,
      }}
    />
  );
}

import React, { type CSSProperties, type ReactNode } from "react";
import { AbsoluteFill, Easing, Series, interpolate, interpolateColors, spring, useCurrentFrame, useVideoConfig } from "remotion";
import { demoAsset } from "@/lib/demo-assets";
import {
  TransitionSeries,
  linearTiming,
  type TransitionPresentation,
  type TransitionPresentationComponentProps,
} from "@remotion/transitions";
import { loadFont as loadSans } from "@remotion/google-fonts/Manrope";
import { loadFont as loadMono } from "@remotion/google-fonts/GeistMono";

import { RemocnUIProvider } from "@/lib/remocn-ui";
import { Backdrop } from "@/components/remocn/backdrop";
import { GlassCodeBlock } from "@/components/remocn/glass-code-block";
import { SharedAxisZ } from "@/components/remocn/shared-axis-z";
import { LogoEnter, type Logo } from "@/components/remocn/logo-enter";
import { useBlurInTransition } from "@/components/remocn/use-blur-in-transition";
import { BlurIn } from "@/components/remocn/blur-in";
import { TerminalSimulator } from "@/components/remocn/terminal-simulator";
import { CheckIcon, CopyIcon } from "lucide-react";

// Bind both fonts to the CSS variables the remocn components read.
const { fontFamily: SANS_FAMILY } = loadSans("normal", {
  subsets: ["latin"],
  weights: ["400", "500", "600", "700", "800"],
});
const { fontFamily: MONO_FAMILY } = loadMono("normal", {
  subsets: ["latin"],
  weights: ["400", "700"],
});

const SANS =
  "var(--font-geist-sans), -apple-system, BlinkMacSystemFont, sans-serif";
const MONO = "var(--font-geist-mono), ui-monospace, SFMono-Regular, monospace";

// Render-engine palette — Remotion blue primary, cyan secondary.
const BLUE = "#5b9dff";
const CYAN = "#34d9e6";
const INK = "#fafafa";
const FAINT = "rgba(250,250,250,0.42)";

// ---------------------------------------------------------------------------
// Scene timings (frames @ 30fps), one per beat. Transitions overlap.
// ---------------------------------------------------------------------------
const S_INTRO = 140; // three questions via shared-axis-z
const S_STOP = 46; //   STOP — scale-down-fade
const S_ONEAPI = 70; //  One API, different providers
const S_ADAPTERS = 85; // render + lambda cards
const S_INSTALL = 72; // terminal install
const S_CODE = 135; //   code example (GlassCodeBlock)
const S_WORKING = 80; // working with — logo-enter
const S_OUTRO = 100; //  render-sdk + install pill

const T_ZOOM = 18; //  intro → stop (punch in)
const T_X = 14; //      generic crossfade
const T_BLUR = 16; //   adapters → install (background clash)
const T_OUT = 20; //    working → outro

export const RENDER_SDK_DURATION =
  S_INTRO +
  S_STOP +
  S_ONEAPI +
  S_ADAPTERS +
  S_INSTALL +
  S_CODE +
  S_WORKING +
  S_OUTRO -
  (T_ZOOM + T_X + T_X + T_BLUR + T_X + T_X + T_OUT);

// ---------------------------------------------------------------------------
// Reveal — blur-in wrapper driven by useBlurInTransition.
// ---------------------------------------------------------------------------
const Reveal: React.FC<{
  children: ReactNode;
  delay?: number;
  distance?: number;
  blur?: number;
  duration?: number;
  display?: CSSProperties["display"];
}> = ({
  children,
  delay = 0,
  distance = 16,
  blur = 10,
  duration = 20,
  display = "block",
}) => {
  const style = useBlurInTransition(
    [{ at: delay, state: "revealed", duration }],
    { direction: "up", distance, blur },
  );
  return (
    <BlurIn style={style} display={display}>
      {children}
    </BlurIn>
  );
};

// ---------------------------------------------------------------------------
// Mark — inline marker swipe behind a phrase.
// ---------------------------------------------------------------------------
const Mark: React.FC<{
  children: string;
  color?: string;
  startFrame?: number;
}> = ({ children, color = BLUE, startFrame = 8 }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const scaleX = spring({
    frame: frame - startFrame,
    fps,
    config: { damping: 15, mass: 0.8 },
  });
  const textColor = interpolateColors(
    interpolate(scaleX, [0.45, 0.85], [0, 1], {
      extrapolateLeft: "clamp",
      extrapolateRight: "clamp",
    }),
    [0, 1],
    [INK, "#0a0a0a"],
  );
  return (
    <span
      style={{
        position: "relative",
        display: "inline-block",
        whiteSpace: "nowrap",
      }}
    >
      <span
        aria-hidden
        style={{
          position: "absolute",
          inset: "-0.02em -0.12em",
          background: color,
          borderRadius: 6,
          transformOrigin: "left center",
          transform: `scaleX(${scaleX})`,
          zIndex: 0,
        }}
      />
      <span style={{ position: "relative", zIndex: 1, color: textColor }}>
        {children}
      </span>
    </span>
  );
};

// ===========================================================================
// Scene 1 — Intro. Three pain questions, each entering via shared-axis-z, in a
// single accent color. A Series resets the frame so each transition plays clean.
// ===========================================================================
const Q1 = "Building a render queue?";
const Q2 = "Two renderers — self-hosted and Lambda?";
const Q3 = "Reusing render code across projects?";

const IntroScene: React.FC = () => (
  <AbsoluteFill style={{ padding: "0 90px" }}>
    <Series>
      <Series.Sequence durationInFrames={42} layout="none">
        <SharedAxisZ
          fromText=""
          toText={Q1}
          fontSize={44}
          fontWeight={600}
          color={"#FFFFFF"}
        />
      </Series.Sequence>
      <Series.Sequence durationInFrames={46} layout="none">
        <SharedAxisZ
          fromText={Q1}
          toText={Q2}
          fontSize={44}
          fontWeight={600}
          color={"#FFFFFF"}
        />
      </Series.Sequence>
      <Series.Sequence durationInFrames={52} layout="none">
        <SharedAxisZ
          fromText={Q2}
          toText={Q3}
          fontSize={44}
          fontWeight={600}
          color={"#FFFFFF"}
        />
      </Series.Sequence>
    </Series>
  </AbsoluteFill>
);

// ===========================================================================
// Scene 2 — STOP. scale-down-fade settles a single hard word, then lets it go.
// ===========================================================================
const StopScene: React.FC = () => (
  <AbsoluteFill style={{ alignItems: "center", justifyContent: "center" }}>
    <SharedAxisZ
      fromText={""}
      toText={"Stop"}
      fontSize={200}
      fontWeight={600}
      color={"#FFFFFF"}
    />
  </AbsoluteFill>
);

// ===========================================================================
// Scene 3 — One API, different providers.
// ===========================================================================
const OneApiScene: React.FC = () => (
  <AbsoluteFill
    style={{
      alignItems: "center",
      justifyContent: "center",
      flexDirection: "column",
      gap: 14,
    }}
  >
    <Reveal delay={4} distance={20} blur={12} duration={22}>
      <h1
        style={{
          margin: 0,
          fontFamily: SANS,
          fontWeight: 500,
          fontSize: 48,
          color: INK,
          textAlign: "center",
        }}
      >
        Use Render SDK
      </h1>
    </Reveal>
    <Reveal delay={16} distance={16} blur={10}>
      <h2
        style={{
          margin: 0,
          fontFamily: SANS,
          fontWeight: 600,
          fontSize: 32,
          color: INK,
          textAlign: "center",
        }}
      >
        <Mark color={BLUE} startFrame={26}>
          One API
        </Mark>{" "}
        Different providers
      </h2>
    </Reveal>
  </AbsoluteFill>
);

// ===========================================================================
// Scene 4 — Adapters: render + lambda cards.
// ===========================================================================
const AdapterCard: React.FC<{
  accent: string;
  title: string;
  pkg: string;
  desc: string;
  call: string;
  delay: number;
}> = ({ accent, title, pkg, desc, call, delay }) => (
  <Reveal delay={delay} distance={36} blur={12} duration={20}>
    <div
      style={{
        width: 360,
        display: "flex",
        flexDirection: "column",
        gap: 14,
        padding: "28px 30px",
        borderRadius: 20,
        background: "rgba(10,10,10,0.55)",
        border: `1px solid ${accent}44`,
        boxShadow: "0 20px 50px rgba(0,0,0,0.45)",
      }}
    >
      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
        <span
          style={{
            width: 11,
            height: 11,
            borderRadius: "50%",
            background: accent,
          }}
        />
        <span
          style={{
            fontFamily: SANS,
            fontWeight: 700,
            fontSize: 28,
            color: INK,
          }}
        >
          {title}
        </span>
      </div>
      <span style={{ fontFamily: MONO, fontSize: 16, color: "#a1a1aa" }}>
        {pkg}
      </span>
      <span
        style={{
          fontFamily: SANS,
          fontSize: 18,
          color: "rgba(255,255,255,0.7)",
        }}
      >
        {desc}
      </span>
      <span
        style={{
          marginTop: 4,
          alignSelf: "flex-start",
          fontFamily: MONO,
          fontSize: 15,
          color: accent,
          padding: "7px 14px",
          borderRadius: 10,
          background: `${accent}1f`,
        }}
      >
        {call}
      </span>
    </div>
  </Reveal>
);

const AdaptersScene: React.FC = () => (
  <AbsoluteFill
    style={{
      alignItems: "center",
      justifyContent: "center",
      flexDirection: "column",
      gap: 36,
    }}
  >
    <Reveal delay={2} distance={16} blur={10}>
      <h2
        style={{
          margin: 0,
          fontFamily: SANS,
          fontWeight: 600,
          fontSize: 40,
          color: INK,
          textAlign: "center",
        }}
      >
        Two adapters, one interface
      </h2>
    </Reveal>
    <div style={{ display: "flex", gap: 36 }}>
      <AdapterCard
        accent={BLUE}
        title="Render"
        pkg="@remotion/renderer"
        desc="Local & self-hosted rendering."
        call="serverAdapter()"
        delay={8}
      />
      <AdapterCard
        accent={CYAN}
        title="Lambda"
        pkg="@remotion/lambda"
        desc="Serverless rendering at scale."
        call="lambdaAdapter()"
        delay={16}
      />
    </div>
  </AbsoluteFill>
);

// ===========================================================================
// Scene 5 — Install (no heading). terminal-cursor-zoom dollies across the typed
// install command.
// ===========================================================================
const InstallScene: React.FC = () => (
  <AbsoluteFill>
    <TerminalSimulator
      lines={[{ text: "bun install @remocn/render-sdk", type: "command", delay: 0 }]}
      fontSize={22}
      title="~/code/my-app"
      charsPerFrame={2}
    />
  </AbsoluteFill>
);

// ===========================================================================
// Scene 6 — Code Example (from the docs), shown in a GlassCodeBlock.
// ===========================================================================
const CODE_EXAMPLE = `import { RenderSdk } from "@remocn/render-sdk";
import { serverAdapter } from "@remocn/render-sdk/server";

const sdk = new RenderSdk({ adapter: serverAdapter() });

const renderId = await sdk.start({
  compositionId: "MyVideo",
  inputProps: { title: "Hello" },
});

await sdk.waitForCompletion(renderId, {
  onProgress: (p) => console.log(p),
});

const url = await sdk.getUrl(renderId);`;

const CodeScene: React.FC = () => (
  <AbsoluteFill
    style={{
      alignItems: "center",
      justifyContent: "center",
      flexDirection: "column",
      gap: 26,
    }}
  >
    <Reveal delay={2} distance={16} blur={10}>
      <h2
        style={{
          margin: 0,
          fontFamily: SANS,
          fontWeight: 600,
          fontSize: 38,
          color: INK,
          textAlign: "center",
        }}
      >
        From start to{" "}
        <Mark color={BLUE} startFrame={12}>
          URL
        </Mark>
      </h2>
    </Reveal>
    <Reveal delay={8} distance={40} blur={14} duration={22}>
      <div style={{ position: "relative", width: 760, height: 470 }}>
        <GlassCodeBlock
          code={CODE_EXAMPLE}
          title="render.ts"
          width={760}
          height={470}
          fontSize={15}
          staggerFrames={2}
        />
      </div>
    </Reveal>
  </AbsoluteFill>
);

// ===========================================================================
// Scene 7 — Working with. Framework brand chips spring in via logo-enter.
// ===========================================================================
const NextMark: React.FC = () => (
  <svg width={54} height={54} viewBox="0 0 180 180">
    <mask
      height={180}
      id="rsdk_next_mask"
      maskUnits="userSpaceOnUse"
      width={180}
      x={0}
      y={0}
      style={{ maskType: "alpha" }}
    >
      <circle cx={90} cy={90} fill="black" r={90} />
    </mask>
    <g mask="url(#rsdk_next_mask)">
      <circle cx={90} cy={90} fill="black" r={90} />
      <path
        d="M149.508 157.52L69.142 54H54V125.97H66.1136V69.3836L139.999 164.845C143.333 162.614 146.509 160.165 149.508 157.52Z"
        fill="url(#rsdk_next_p0)"
      />
      <rect fill="url(#rsdk_next_p1)" height={72} width={12} x={115} y={54} />
    </g>
    <defs>
      <linearGradient
        gradientUnits="userSpaceOnUse"
        id="rsdk_next_p0"
        x1={109}
